  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  border-radius: 999px;
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.12rem 0.38rem;
  background: var(--muted);
  color: var(--muted-foreground);
  text-transform: capitalize;
}

/* Relationship list in detail panel */

.relationship-group {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.relationship-group-label {
  font-size: 0.67rem;
  font-weight: 700;
  color: #4e6784;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.relationship-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.25rem 0.35rem;
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.78rem;
  color: #2a4a6b;
}

.relationship-item:hover {
  background: #e8f1fd;
}

/* Provenance section */

.provenance-item {
  border: 1px solid #e2ecf7;
  border-radius: 8px;
  padding: 0.4rem 0.5rem;
  font-size: 0.76rem;
  color: #365879;
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.provenance-evidence {
  font-style: italic;
  color: #4c6583;
}

.provenance-link {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
  font-size: 0.72rem;
  cursor: pointer;
}

.provenance-link:hover {
  text-decoration: underline;
}

/* View tabs */

.view-tabs {
  display: flex;
  gap: 0.2rem;
}

.view-tab {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
  padding: 0.25rem 0.5rem;
  border-radius: 6px;
}

.view-tab:hover {
  background: #e8f1fd;
}

.view-tab--active {
  background: #d0e3fc;
  color: #0e3d6e;
}

/* Graph icon on entity card */

.entity-card-graph-link {
  border: none;
  background: transparent;
  color: #0057cc;
  cursor: pointer;
  padding: 0.15rem;
  line-height: 1;
  font-size: 0.8rem;
  border-radius: 4px;
}

.entity-card-graph-link:hover {
  background: #e8f1fd;
}

/* Message highlight animation (graph → chat navigation) */

@keyframes highlight-message {
  0% {
    background: rgba(0, 87, 204, 0.15);
  }
  100% {
    background: transparent;
  }
}

.animate-highlight {
  animation: highlight-message 2s ease-out;
}

