  1→import { RecordId } from "surrealdb";
  2→import type { EntityActionRequest } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { logError, logInfo } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→import {
  9→  confirmDecisionRecord,
 10→  isEntityInWorkspace,
 11→  parseRecordIdString,
 12→  type GraphEntityTable,
 13→} from "../graph/queries";
 14→
 15→export function createEntityActionsHandler(
 16→  deps: ServerDependencies,
 17→): (entityId: string, request: Request) => Promise<Response> {
 18→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 19→}
 20→
 21→async function handleEntityAction(
 22→  deps: ServerDependencies,
 23→  entityId: string,
 24→  request: Request,
 25→): Promise<Response> {
 26→  let body: EntityActionRequest;
 27→  try {
 28→    body = await request.json() as EntityActionRequest;
 29→  } catch {
 30→    return jsonError("invalid JSON body", 400);
 31→  }
 32→
 33→  if (!body.action || !["confirm", "override", "complete"].includes(body.action)) {
 34→    return jsonError("action must be one of: confirm, override, complete", 400);
 35→  }
 36→
 37→  const url = new URL(request.url);
 38→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 39→  if (!workspaceId) {
 40→    return jsonError("workspaceId is required", 400);
 41→  }
 42→
 43→  let workspaceRecord;
 44→  try {
 45→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 46→  } catch (error) {
 47→    if (error instanceof HttpError) {
 48→      return jsonError(error.message, error.status);
 49→    }
 50→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 51→    return jsonError("failed to resolve workspace", 500);
 52→  }
 53→
 54→  try {
 55→    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question"];
 56→    const entityRecord = parseRecordIdString(entityId, entityTables);
 57→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord);
 58→    if (!scoped) {
 59→      return jsonError("entity is outside the current workspace scope", 403);
 60→    }
 61→
 62→    const table = entityRecord.table.name;
 63→    const now = new Date();
 64→
 65→    if (body.action === "confirm" && table === "decision") {
 66→      await confirmDecisionRecord({
 67→        surreal: deps.surreal,
 68→        decisionRecord: entityRecord as RecordId<"decision", string>,
 69→        confirmedAt: now,
 70→        notes: body.notes,
