body {
  margin: 0;
  min-height: 100vh;
}

.app-shell {
  width: min(1340px, 100%);
  margin: 0 auto;
  padding: 1.5rem 1rem 2.2rem;
}

.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
}

.nav-link {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
}

.app-main {
  border: 1px solid #bbd2ef;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.8);
  box-shadow: 0 16px 40px rgba(0, 36, 85, 0.08);
}

.reachat-page {
  min-height: 72vh;
  display: flex;
  flex-direction: column;
  padding: 0.75rem;
  gap: 0.75rem;
}

.reachat-header {
  font-size: 0.9rem;
  font-weight: 700;
  color: #194372;
}

.workspace-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.6rem;
  border: 1px solid #c8d9ef;
  border-radius: 12px;
  background: #f4f9ff;
  padding: 0.6rem 0.8rem;
}

.seed-toggle {
  border: 1px solid #9fbfe4;
  border-radius: 10px;
  background: #fff;
  color: #1c4f86;
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.workspace-state {
  margin-left: 0.6rem;
  font-size: 0.8rem;
  font-weight: 600;
  color: #2a577f;
}

.pending-file {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  font-size: 0.8rem;
}

.pending-file button {
  border: 1px solid #9ab9dd;
  border-radius: 8px;
  background: #fff;
  color: #1d4e84;
  cursor: pointer;
  padding: 0.2rem 0.45rem;
}

.onboarding-action-buttons {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  padding: 0.1rem 0.1rem 0.2rem;
}

.onboarding-action-buttons button {
  border: 1px solid #9fbfe4;
  border-radius: 10px;
  background: #fff;
  color: #1c4f86;
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.onboarding-action-buttons button:disabled {
  cursor: not-allowed;
  color: #6f88a6;
  border-color: #c2d4ea;
}

.workspace-layout {
  display: grid;
  grid-template-columns: 240px minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 64vh;
}

.chat-main {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 0;
}

.chat-main--with-seeds {
  grid-template-columns: minmax(0, 1fr) 280px;
}

/* Conversation sidebar */
.conversation-sidebar {
  border: 1px solid #c7daf2;
  border-radius: 14px;
  background: #fbfdff;
  padding: 0.5rem;
  overflow-y: auto;
  max-height: 72vh;
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
}

.sidebar-new-conversation {
  width: 100%;
  border: 1px solid #9fbfe4;
  border-radius: 10px;
  background: #1f6ad1;
  color: #fff;
  padding: 0.45rem 0.6rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
  margin-bottom: 0.25rem;
}

.sidebar-new-conversation:disabled {
  background: #97b4d9;
  cursor: not-allowed;
}

.sidebar-project-group {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.sidebar-project-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.3rem 0.4rem;
}

.sidebar-project-name {
  font-size: 0.72rem;
  font-weight: 700;
  color: #1f4f80;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.sidebar-unlinked-label {
