  let body: unknown;
  try {
    body = await request.json();
  } catch {
    return jsonError("invalid JSON body", 400);
  }

  const parsed = acceptWorkItemSchema.safeParse(body);
  if (!parsed.success) {
    return jsonError(`invalid work item: ${parsed.error.message}`, 400);
  }

