18→  conversationRecord: RecordId<"conversation", string>;
19→  workspaceRecord: RecordId<"workspace", string>;
20→  currentMessageRecord: RecordId<"message", string>;
21→  latestUserText: string;
22→  workspaceOwnerRecord?: RecordId<"person", string>;
23→  messages: ConversationMessage[];
24→  onToken: (token: string) => Promise<void> | void;
25→}): Promise<{ text: string }> {
26→  const context = await buildChatContext({
27→    surreal: input.surreal,
28→    conversationRecord: input.conversationRecord,
29→    workspaceRecord: input.workspaceRecord,
30→  });
31→
32→  const system = buildSystemPrompt(context);
33→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
34→    role: message.role,
35→    content: message.text,
36→  }));
37→
38→  const result = streamText({
39→    model: input.model,
40→    system,
41→    messages: modelMessages,
42→    tools: createOrchestratorTools({
43→      surreal: input.surreal,
44→      pmModel: input.pmModel,
45→      embeddingModel: input.embeddingModel,
46→      embeddingDimension: input.embeddingDimension,
47→      extractionModelId: input.extractionModelId,
48→    }),
49→    experimental_context: {
50→      actor: "orchestrator",
51→      workspaceRecord: input.workspaceRecord,
52→      conversationRecord: input.conversationRecord,
53→      currentMessageRecord: input.currentMessageRecord,
54→      latestUserText: input.latestUserText,
55→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
56→    },
57→    stopWhen: stepCountIs(5),
58→  });
59→
60→  let text = "";
61→  for await (const part of result.fullStream) {
62→    if (part.type !== "text-delta") {
63→      continue;
64→    }
65→
66→    text = `${text}${part.text}`;
67→    await input.onToken(part.text);
68→  }
69→
70→  if (text.trim().length === 0) {
71→    text = await result.text;
72→  }
73→
74→  return {
75→    text: text.trim(),
76→  };
77→}
