 91→  }
 92→
 93→  return entities
 94→    .slice(0, 20)
 95→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
 96→    .join("\n");
 97→}
