 99→function formatProjectList(projects: WorkspaceProjectSummary[]): string {
100→  if (projects.length === 0) {
101→    return "- none";
102→  }
103→
104→  return projects
105→    .slice(0, 15)
106→    .map((project) => `- ${project.name} [id: ${project.id}] active tasks: ${project.activeTaskCount}`)
107→    .join("\n");
