113→  }
114→
115→  return decisions
116→    .slice(0, 15)
117→    .map((decision) => {
118→      const project = decision.project ? ` project: ${decision.project}` : "";
119→      return `- ${decision.name} [id: ${decision.id}] status: ${decision.status}${project}`;
120→    })
