128→
129→  return questions
130→    .slice(0, 15)
131→    .map((question) => {
132→      const project = question.project ? ` project: ${question.project}` : "";
133→      return `- ${question.name} [id: ${question.id}]${project}`;
134→    })
135→    .join("\n");
136→}
137→
138→function formatObservationList(observations: ObservationSummary[]): string {
139→  if (observations.length === 0) {
140→    return "- none";
141→  }
142→
143→  return observations
144→    .slice(0, 10)
145→    .map((observation) => {
146→      const category = observation.category ? `, ${observation.category}` : "";
147→      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
148→    })
149→    .join("\n");
150→}
