  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction, OnboardingSeedItem } from "../../shared/contracts";
  3→import { buildExtractionComponentBlock } from "../extraction/components";
  4→import { loadAssistantConversationContext, loadConversationGraphContext, loadExtractionConversationContext } from "../extraction/context-loaders";
  5→import { ingestAttachment } from "../extraction/document-ingestion";
  6→import { persistEmbeddings } from "../extraction/embedding-writeback";
  7→import { extractStructuredGraph } from "../extraction/extract-graph";
  8→import { appendExtractedTools, persistExtractionOutput } from "../extraction/persist-extraction";
  9→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, SourceRecord, WorkspaceRow } from "../extraction/types";
 10→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 11→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 12→import { generateOnboardingAssistantReply } from "../onboarding/onboarding-reply";
 13→import type { ServerDependencies } from "../runtime/types";
 14→import { runOrchestrator } from "./handler";
 15→import { getWorkspaceOwnerRecord } from "../graph/queries";
 16→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 17→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 18→
 19→export async function processChatMessage(input: {
 20→  deps: ServerDependencies;
 21→  conversationId: string;
 22→  messageId: string;
 23→  workspaceRecord: RecordId<"workspace", string>;
 24→  userMessageRecord: RecordId<"message", string>;
 25→  userText: string;
 26→  attachment?: IncomingAttachment;
 27→  onboardingAction?: OnboardingAction;
 28→}): Promise<void> {
 29→  const startedAt = performance.now();
 30→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 31→    conversationId: input.conversationId,
 32→    messageId: input.messageId,
 33→    workspaceId: input.workspaceRecord.id as string,
 34→    hasAttachment: input.attachment !== undefined,
 35→  });
 36→
 37→  try {
 38→    const now = new Date();
 39→    const conversationRecord = new RecordId("conversation", input.conversationId);
 40→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 41→    if (!workspace) {
 42→      throw new Error("workspace not found");
 43→    }
 44→
 45→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 46→    if (!conversation) {
 47→      throw new Error("conversation not found");
 48→    }
 49→
 50→    const assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 51→    const extractionConversationContext = await loadExtractionConversationContext({
 52→      surreal: input.deps.surreal,
 53→      conversationId: input.conversationId,
 54→      currentMessageRecord: input.userMessageRecord,
 55→    });
 56→    const extractionGraphContext = await loadConversationGraphContext(input.deps.surreal, input.conversationId, 60);
 57→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
 58→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
 59→    const persistedEntities: ExtractedEntity[] = [];
 60→    const persistedRelationships: ExtractedRelationship[] = [];
 61→    const seedItems: OnboardingSeedItem[] = [];
 62→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 63→    const extractedTools: string[] = [];
 64→    const unresolvedAssigneeNames = new Set<string>();
 65→
 66→    if (input.attachment) {
 67→      const ingestion = await ingestAttachment({
 68→        surreal: input.deps.surreal,
 69→        extractionModel: input.deps.extractionModel,
 70→        embeddingModel: input.deps.embeddingModel,
 71→        embeddingDimension: input.deps.config.embeddingDimension,
 72→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
 73→        extractionModelId: input.deps.config.extractionModelId,
 74→        workspaceRecord: input.workspaceRecord,
 75→        conversationRecord,
 76→        userMessageRecord: input.userMessageRecord,
 77→        attachment: input.attachment,
 78→        workspaceName: workspace.name,
 79→        projectNames: workspaceProjectNames,
 80→        now,
 81→        onChunkResult: (chunkResult) => {
 82→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
 83→            input.deps.sse.emitEvent(input.messageId, {
 84→              type: "extraction",
 85→              messageId: input.messageId,
 86→              entities: chunkResult.entities,
 87→              relationships: chunkResult.relationships,
 88→            });
 89→          }
 90→          if (chunkResult.seeds.length > 0) {
 91→            input.deps.sse.emitEvent(input.messageId, {
 92→              type: "onboarding_seed",
 93→              messageId: input.messageId,
 94→              seeds: chunkResult.seeds,
 95→            });
 96→          }
 97→        },
 98→      });
 99→
100→      persistedEntities.push(...ingestion.entities);
101→      persistedRelationships.push(...ingestion.relationships);
102→      seedItems.push(...ingestion.seeds);
103→      embeddingTargets.push(...ingestion.embeddingTargets);
104→      extractedTools.push(...ingestion.tools);
105→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
106→        unresolvedAssigneeNames.add(unresolvedName);
107→      }
108→    }
109→
110→    const textExtraction = await extractStructuredGraph({
111→      extractionModel: input.deps.extractionModel,
112→      conversationHistory: extractionConversationContext.conversationHistory,
113→      currentMessage: extractionConversationContext.currentMessage,
114→      graphContext: extractionGraphContext,
115→      sourceText: input.userText,
116→      onboarding: !workspace.onboarding_complete,
117→      workspaceName: workspace.name,
118→      projectNames: workspaceProjectNames,
119→    });
120→
121→    const textPersistence = await persistExtractionOutput({
122→      surreal: input.deps.surreal,
123→      embeddingModel: input.deps.embeddingModel,
124→      embeddingDimension: input.deps.config.embeddingDimension,
125→      extractionModelId: input.deps.config.extractionModelId,
126→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
127→      workspaceRecord: input.workspaceRecord,
128→      sourceRecord: input.userMessageRecord as SourceRecord,
129→      sourceKind: "message",
130→      sourceLabel: input.userText.slice(0, 140),
131→      promptText: input.userText,
132→      output: textExtraction,
133→      sourceMessageRecord: input.userMessageRecord,
134→      extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map((row) => row.id.id as string),
135→      now,
136→    });
137→
138→    persistedEntities.push(...textPersistence.entities);
139→    persistedRelationships.push(...textPersistence.relationships);
140→    seedItems.push(...textPersistence.seeds);
141→    embeddingTargets.push(...textPersistence.embeddingTargets);
142→    extractedTools.push(...textPersistence.tools);
143→    for (const unresolvedName of textPersistence.unresolvedAssigneeNames) {
144→      unresolvedAssigneeNames.add(unresolvedName);
145→    }
146→
147→    const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
148→    await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
149→
150→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
151→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
152→
153→    const onboardingBefore = workspace.onboarding_complete
154→      ? "complete"
155→      : workspace.onboarding_summary_pending
156→        ? "summary_pending"
157→        : "active";
158→
159→    const onboardingAfter = await transitionOnboardingState({
160→      surreal: input.deps.surreal,
161→      workspaceRecord: input.workspaceRecord,
162→      workspace,
163→      onboardingAction: input.onboardingAction,
164→      now,
165→    });
166→
167→    let assistantText = "";
168→    let assistantSuggestions: string[] = [];
169→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
170→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
171→    );
172→
173→    if (onboardingAfter === "complete") {
174→      const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
175→        surreal: input.deps.surreal,
176→        workspaceRecord: input.workspaceRecord,
177→      });
178→
179→      const graphAwareResponse = await runOrchestrator({
180→        surreal: input.deps.surreal,
181→        model: input.deps.assistantModel,
182→        pmModel: input.deps.pmModel,
183→        embeddingModel: input.deps.embeddingModel,
184→        embeddingDimension: input.deps.config.embeddingDimension,
185→        extractionModelId: input.deps.config.extractionModelId,
186→        conversationRecord,
187→        workspaceRecord: input.workspaceRecord,
188→        currentMessageRecord: input.userMessageRecord,
189→        latestUserText: input.userText,
190→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
191→        messages: assistantContextRows.map((row) => ({
192→          role: row.role,
193→          text: row.text,
194→        })),
195→        onToken: async (token) => {
196→          input.deps.sse.emitEvent(input.messageId, {
197→            type: "token",
198→            messageId: input.messageId,
199→            token,
200→          });
201→        },
202→      });
203→
204→      assistantText = graphAwareResponse.text.trim();
205→    } else {
206→      const assistantReply = await generateOnboardingAssistantReply({
207→        assistantModel: input.deps.assistantModel,
208→        surreal: input.deps.surreal,
209→        onboardingState: onboardingAfter,
210→        contextRows: assistantContextRows,
211→        latestUserText: input.userText,
212→        workspaceRecord: input.workspaceRecord,
213→        latestEntities: persistedEntities.map((entity) => ({
214→          kind: entity.kind,
215→          text: entity.text,
216→          confidence: entity.confidence,
217→        })),
218→        latestTools: dedupedTools,
219→      });
220→
221→      assistantText = assistantReply.message.trim();
222→      assistantSuggestions = assistantReply.suggestions;
223→
224→      for (const token of assistantText.split(" ")) {
225→        input.deps.sse.emitEvent(input.messageId, {
226→          type: "token",
227→          messageId: input.messageId,
228→          token: `${token} `,
229→        });
230→        await new Promise((resolve) => setTimeout(resolve, 25));
231→      }
232→    }
233→
234→    assistantSuggestions = sanitizeAssistantSuggestions(
235→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
236→      3,
237→    );
238→
239→    const summaryBlock = buildExtractionComponentBlock(
240→      persistedEntities,
241→      persistedRelationships,
242→      input.deps.config.extractionDisplayThreshold,
243→    );
244→
245→    if (summaryBlock) {
246→      if (onboardingAfter === "complete") {
247→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
248→        for (const token of streamChunk.split(" ")) {
249→          input.deps.sse.emitEvent(input.messageId, {
250→            type: "token",
251→            messageId: input.messageId,
252→            token: `${token} `,
253→          });
254→        }
255→      }
256→
257→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
258→    }
259→
260→    if (assistantText.trim().length === 0) {
261→      assistantText = "I could not generate a response for that request.";
262→    }
263→
264→    const assistantMessageRecord = new RecordId("message", input.messageId);
265→    await input.deps.surreal.create(assistantMessageRecord).content({
266→      conversation: conversationRecord,
267→      role: "assistant",
268→      text: assistantText,
269→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
270→      createdAt: now,
271→    });
272→
273→    await input.deps.surreal.update(conversationRecord).merge({
274→      updatedAt: now,
275→    });
276→
277→    void persistEmbeddings({
278→      surreal: input.deps.surreal,
279→      embeddingModel: input.deps.embeddingModel,
280→      embeddingDimension: input.deps.config.embeddingDimension,
281→      assistantMessageRecord,
282→      assistantText,
283→      entities: embeddingTargets,
284→    }).catch(() => undefined);
285→
286→    input.deps.sse.emitEvent(input.messageId, {
287→      type: "extraction",
288→      messageId: input.messageId,
289→      entities: persistedEntities,
290→      relationships: persistedRelationships,
291→    });
292→
293→    if (seedItems.length > 0) {
294→      input.deps.sse.emitEvent(input.messageId, {
295→        type: "onboarding_seed",
296→        messageId: input.messageId,
297→        seeds: seedItems,
298→      });
299→    }
300→
301→    if (onboardingBefore !== onboardingAfter) {
302→      input.deps.sse.emitEvent(input.messageId, {
303→        type: "onboarding_state",
304→        messageId: input.messageId,
305→        onboardingState: onboardingAfter,
306→      });
307→    }
308→
309→    input.deps.sse.emitEvent(input.messageId, {
310→      type: "assistant_message",
311→      messageId: input.messageId,
312→      text: assistantText,
313→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
314→    });
315→
316→    input.deps.sse.emitEvent(input.messageId, {
317→      type: "done",
318→      messageId: input.messageId,
319→    });
320→
321→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
322→      conversationId: input.conversationId,
323→      messageId: input.messageId,
324→      workspaceId: input.workspaceRecord.id as string,
325→      entityCount: persistedEntities.length,
326→      relationshipCount: persistedRelationships.length,
327→      seedCount: seedItems.length,
328→      durationMs: elapsedMs(startedAt),
329→    });
330→  } catch (error) {
331→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
332→      conversationId: input.conversationId,
333→      messageId: input.messageId,
334→      workspaceId: input.workspaceRecord.id as string,
335→      durationMs: elapsedMs(startedAt),
336→    });
337→    const errorText = userFacingError(error, "chat processing failed");
338→    input.deps.sse.emitEvent(input.messageId, {
339→      type: "error",
340→      messageId: input.messageId,
341→      error: errorText,
342→    });
343→  }
344→}
345→
346→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
347→  return [...new Set(suggestions.map((value) => value.trim()))]
348→    .filter((value) => value.length > 0 && value.length <= 140)
349→    .slice(0, limit);
350→}
