11→export function createCreateObservationTool(deps: ChatToolDeps) {
12→  return tool({
13→    description:
14→      "Create an observation in the workspace graph. Use this for warnings, conflicts, or notable facts that should be tracked.",
15→    inputSchema: z.object({
16→      text: z.string().min(1).describe("Observation text"),
17→      severity: z.enum(["info", "warning", "conflict"]).describe("Observation severity"),
18→      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional observation category"),
19→      related_entity_id: z
20→        .string()
21→        .optional()
22→        .describe("Optional related entity id (project/feature/task/decision/question)"),
23→    }),
24→    execute: async (input, options) => {
25→      const context = requireToolContext(options);
26→
27→      const relatedRecord = input.related_entity_id
28→        ? parseRecordIdString(
29→            input.related_entity_id,
30→            ["project", "feature", "task", "decision", "question"],
31→          ) as RecordId<"project" | "feature" | "task" | "decision" | "question", string>
32→        : undefined;
33→
34→      if (relatedRecord) {
35→        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, relatedRecord);
36→        if (!scoped) {
37→          throw new Error("related entity is outside the current workspace scope");
38→        }
39→      }
40→
41→      const embedding = await createEmbeddingVector(deps.embeddingModel, input.text, deps.embeddingDimension);
42→      if (!embedding) {
43→        throw new Error("failed to create embedding for create_observation");
44→      }
45→
46→      const observationRecord = await createObservation({
47→        surreal: deps.surreal,
48→        workspaceRecord: context.workspaceRecord,
49→        text: input.text,
50→        severity: input.severity,
51→        ...(input.category ? { category: input.category } : {}),
52→        sourceAgent: context.actor,
53→        now: new Date(),
54→        sourceMessageRecord: context.currentMessageRecord,
55→        ...(relatedRecord ? { relatedRecord } : {}),
56→        embedding,
57→      });
58→
59→      return {
60→        observation_id: `observation:${observationRecord.id as string}`,
61→        severity: input.severity,
62→        status: "open",
63→      };
64→    },
65→  });
66→}
